content:
{
  "sentences": [
    {
      "text": "雖然今天很忙，我還是去運動了。",
      "pinyin": "Suīrán jīntiān hěn máng, wǒ háishì qù yùndòng le.",
      "pinyin_numeric": "sui1ran2 jin1tian1 hen3 mang2, wo3 hai2shi4 qu4 yun4dong4 le0.",
      "translation_en": "Although I was very busy today, I still went to exercise.",
      "translation_ko": "오늘은 바빴지만, 저는 여전히 운동하러 갔어요."
    },
    {
      "text": "他雖然不太會說中文，但是還是努力跟我們聊天。",
      "pinyin": "Tā suīrán bù tài huì shuō Zhōngwén, dànshì háishì nǔlì gēn wǒmen liáotiān.",
      "pinyin_numeric": "ta1 sui1ran2 bu4 tai4 hui4 shuo1 Zhong1wen2, dan4shi4 hai2shi4 nu3li4 gen1 wo3men liao2tian1.",
      "translation_en": "Although he doesn't speak Chinese very well, he still tried hard to chat with us.",
      "translation_ko": "그는 중국어를 잘 못하지만, 그래도 우리와 열심히 대화했어요."
    },
    {
      "text": "這家餐廳很貴，不過我還是想試試看。",
      "pinyin": "Zhè jiā cāntīng hěn guì, búguò wǒ háishì xiǎng shì shì kàn.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 hen3 gui4, bu2guo4 wo3 hai2shi4 xiang3 shi4 shi4 kan4.",
      "translation_en": "This restaurant is very expensive, but I still want to try it.",
      "translation_ko": "이 식당은 매우 비싸지만, 그래도 한번 시도해 보고 싶어요."
    },
    {
      "text": "即使下雨，他還是每天走路去上班。",
      "pinyin": "Jíshǐ xià yǔ, tā háishì měitiān zǒulù qù shàngbān.",
      "pinyin_numeric": "ji2shi3 xia4 yu3, ta1 hai2shi4 mei3tian1 zou3lu4 qu4 shang4ban1.",
      "translation_en": "Even if it rains, he still walks to work every day.",
      "translation_ko": "비가 와도 그는 여전히 매일 걸어서 출근해요."
    },
    {
      "text": "她雖然很累，可是還是幫我準備晚餐。",
      "pinyin": "Tā suīrán hěn lèi, kěshì háishì bāng wǒ zhǔnbèi wǎncān.",
      "pinyin_numeric": "ta1 sui1ran2 hen3 lei4, ke3shi4 hai2shi4 bang1 wo3 zhun3bei4 wan3can1.",
      "translation_en": "Although she was very tired, she still helped me prepare dinner.",
      "translation_ko": "그녀는 매우 피곤했지만, 그래도 저를 위해 저녁을 준비해 줬어요."
    },
    {
      "text": "這件衣服有點貴，可是我還是買了。",
      "pinyin": "Zhè jiàn yīfu yǒudiǎn guì, kěshì wǒ háishì mǎi le.",
      "pinyin_numeric": "zhe4 jian4 yi1fu you3dian3 gui4, ke3shi4 wo3 hai2shi4 mai3 le0.",
      "translation_en": "This piece of clothing is a bit expensive, but I still bought it.",
      "translation_ko": "이 옷은 조금 비싸지만, 그래도 샀어요."
    },
    {
      "text": "就算你不想去，我還是會去。",
      "pinyin": "Jiùsuàn nǐ bù xiǎng qù, wǒ háishì huì qù.",
      "pinyin_numeric": "jiu4suan4 ni3 bu4 xiang3 qu4, wo3 hai2shi4 hui4 qu4.",
      "translation_en": "Even if you don't want to go, I will still go.",
      "translation_ko": "네가 가고 싶지 않아도, 나는 여전히 갈 거예요."
    },
    {
      "text": "儘管他沒有經驗，他還是得到了這份工作。",
      "pinyin": "Jǐnguǎn tā méiyǒu jīngyàn, tā háishì dédào le zhè fèn gōngzuò.",
      "pinyin_numeric": "jin3guan3 ta1 mei2you3 jing1yan4, ta1 hai2shi4 de2dao4 le0 zhe4 fen4 gong1zuo4.",
      "translation_en": "Although he has no experience, he still got this job.",
      "translation_ko": "그는 경험이 없지만, 그래도 이 일자리를 얻었어요."
    },
    {
      "text": "不管天氣好不好，我還是要去公園散步。",
      "pinyin": "Bùguǎn tiānqì hǎo bù hǎo, wǒ háishì yào qù gōngyuán sànbù.",
      "pinyin_numeric": "bu4guan3 tian1qi4 hao3 bu4 hao3, wo3 hai2shi4 yao4 qu4 gong1yuan2 san4bu4.",
      "translation_en": "No matter whether the weather is good or not, I still want to go for a walk in the park.",
      "translation_ko": "날씨가 좋든 안 좋든, 나는 여전히 공원에 산책하러 갈 거예요."
    },
    {
      "text": "他雖然很忙，可是還是會打電話給媽媽。",
      "pinyin": "Tā suīrán hěn máng, kěshì háishì huì dǎ diànhuà gěi māma.",
      "pinyin_numeric": "ta1 sui1ran2 hen3 mang2, ke3shi4 hai2shi4 hui4 da3 dian4hua4 gei3 ma1ma.",
      "translation_en": "Although he is very busy, he still calls his mom.",
      "translation_ko": "그는 매우 바쁘지만, 그래도 엄마에게 전화해요."
    }
  ]
}
